import json
import os
import signal
import subprocess
import threading
import time
from pathlib import Path
from typing import Optional

FISH_SESSION_DIR_FILE = "/tmp/fish_session_dir"
FISH_COLLECTOR_PID_FILE = "/tmp/fish_collector_active"

# Topic hz sampling: window size for rate calculation
TOPIC_HZ_WINDOW_SIZE = 50
# Topic hz: seconds per topic sample
TOPIC_HZ_SAMPLE_SECONDS = 10


def get_session_dir() -> str:
    try:
        return Path(FISH_SESSION_DIR_FILE).read_text().strip()
    except FileNotFoundError:
        return "/tmp/fish_traces/unsorted"


def get_snapshot_dir() -> str:
    d = os.path.join(get_session_dir(), "snapshot")
    os.makedirs(d, exist_ok=True)
    return d


def _find_real_ros2() -> str:
    """Find the real ros2 binary, skipping the FISH wrapper."""
    try:
        result = subprocess.run(
            "which -a ros2 | grep -v /fish/bin | head -1",
            shell=True, text=True, capture_output=True
        )
        path = result.stdout.strip()
        if path:
            return path
    except Exception:
        pass
    return "/opt/ros/humble/bin/ros2"


def _run_cmd(cmd: str, timeout: float = 30.0) -> str:
    """Run a shell command and return stdout."""
    try:
        result = subprocess.run(
            cmd, shell=True, text=True, capture_output=True, timeout=timeout
        )
        return result.stdout.strip()
    except (subprocess.TimeoutExpired, subprocess.CalledProcessError, Exception) as e:
        print(f"[FISH] WARNING: Command failed: {cmd} ({e})")
        return ""


def _ros2_cmd(cmd: str, timeout: float = 30.0) -> str:
    """Run a ros2 CLI command using the real ros2 binary."""
    real_ros2 = _find_real_ros2()
    full_cmd = cmd.replace("ros2 ", f"{real_ros2} ", 1)
    return _run_cmd(full_cmd, timeout=timeout)


